import {
  and,
  desc,
  eq,
  gte,
  ilike,
  lt,
  lte,
  or,
  sql,
} from "drizzle-orm";

import { user } from "@/db-schemas/auth";
import { clientEvents } from "@/db-schemas/client";
import { contractEvents } from "@/db-schemas/client-contract";
import { prospectEvents } from "@/db-schemas/prospect";
import { taskEvents } from "@/db-schemas/task";
import { db } from "@/lib/db/server";

export type AuditLogEntry = {
  changedAt: Date | null;
  changedBy: string | null;
  changedByEmail: string | null;
  changedByImage: string | null;
  changedByName: string | null;
  changedByPhone: string | null;
  entityId: string;
  entityType: "client" | "contract" | "prospect" | "task";
  field: string;
  id: number;
  newValue: string | null;
  oldValue: string | null;
};

type ListAuditLogsInput = {
  changedBy?: string;
  cursor?: string;
  dateFrom?: Date;
  dateTo?: Date;
  entityType?: "client" | "contract" | "prospect" | "task";
  field?: string;
  limit?: number;
  search?: string;
};

const commonSelect = {
  changedAt: sql<Date | null>`{changedAtColumn}`.as("changed_at"),
  changedBy: sql<string>`{changedByColumn}`.as("changed_by"),
  changedByEmail: sql<string | null>`{changedByEmailColumn}`.as("changed_by_email"),
  changedByImage: sql<string | null>`{changedByImageColumn}`.as("changed_by_image"),
  changedByName: sql<string | null>`{changedByNameColumn}`.as("changed_by_name"),
  changedByPhone: sql<string | null>`{changedByPhoneColumn}`.as("changed_by_phone"),
  entityId: sql<string>`{entityIdColumn}`.as("entity_id"),
  entityType: sql<string>`{entityTypeValue}`.as("entity_type"),
  field: sql<string>`{fieldColumn}`.as("field"),
  id: sql<number>`{idColumn}`.as("id"),
  newValue: sql<string | null>`{newValueColumn}`.as("new_value"),
  oldValue: sql<string | null>`{oldValueColumn}`.as("old_value"),
};

function buildConditions(
  table: typeof taskEvents | typeof clientEvents | typeof prospectEvents | typeof contractEvents,
  input: ListAuditLogsInput,
) {
  const conditions = [];

  if (input.changedBy) {
    conditions.push(eq(table.changedBy, input.changedBy));
  }
  if (input.field) {
    conditions.push(eq(table.field, input.field));
  }
  if (input.dateFrom) {
    conditions.push(gte(table.changedAt, input.dateFrom));
  }
  if (input.dateTo) {
    conditions.push(lte(table.changedAt, input.dateTo));
  }
  if (input.search) {
    const searchFilter = or(
      ilike(user.name, `%${input.search}%`),
      ilike(table.field, `%${input.search}%`),
    );
    if (searchFilter) conditions.push(searchFilter);
  }

  return conditions.length > 0 ? and(...conditions) : undefined;
}

function buildCursorCondition(
  table: typeof taskEvents | typeof clientEvents | typeof prospectEvents | typeof contractEvents,
  entityType: string,
  cursor: string,
) {
  try {
    const [timestampStr, idStr, cursorEntityType] = cursor.split("::");
    const cursorTime = new Date(timestampStr);
    const cursorId = Number.parseInt(idStr, 10);
    if (Number.isNaN(cursorId) || Number.isNaN(cursorTime.getTime())) return undefined;

    return and(
      or(
        lt(table.changedAt, cursorTime),
        and(
          eq(table.changedAt, cursorTime),
          lt(table.id, cursorId),
        ),
      ),
      entityType === cursorEntityType ? undefined : undefined,
    );
  } catch {
    return undefined;
  }
}

export async function listAuditLogs(input: ListAuditLogsInput) {
  const {
    changedBy,
    cursor,
    dateFrom,
    dateTo,
    entityType,
    field,
    limit = 50,
    search,
  } = input;

  const eventTypes = entityType
    ? [entityType]
    : (["task", "client", "prospect", "contract"] as const);

  const allRows: AuditLogEntry[] = [];

  for (const type of eventTypes) {
    const table =
      type === "task"
        ? taskEvents
        : type === "client"
          ? clientEvents
          : type === "prospect"
            ? prospectEvents
            : contractEvents;

    const conditions = [];

    const baseConditions = buildConditions(table, input);
    if (baseConditions) conditions.push(baseConditions);

    if (cursor) {
      const cursorCond = buildCursorCondition(table, type, cursor);
      if (cursorCond) conditions.push(cursorCond);
    }

    const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

    const rows = await db
      .select({
        changedAt: table.changedAt,
        changedBy: table.changedBy,
        changedByEmail: user.email,
        changedByImage: user.image,
        changedByName: user.name,
        changedByPhone: user.phoneNumber,
        entityId:
          type === "task"
            ? sql<string>`${taskEvents.taskId}::text`
            : type === "client"
              ? sql<string>`${clientEvents.clientId}::text`
              : type === "prospect"
                ? sql<string>`${prospectEvents.prospectId}::text`
                : sql<string>`${contractEvents.contractId}::text`,
        entityType: sql<string>`${type}::text`.as("entity_type"),
        field: table.field,
        id: table.id,
        newValue: table.newValue,
        oldValue: table.oldValue,
      })
      .from(table)
      .leftJoin(user, eq(table.changedBy, user.id))
      .where(whereClause)
      .orderBy(desc(table.changedAt), desc(table.id))
      .limit(limit + 1);

    for (const row of rows) {
      allRows.push({
        ...row,
        entityType: type,
      });
    }
  }

  allRows.sort((a, b) => {
    const aTime = a.changedAt?.getTime() ?? 0;
    const bTime = b.changedAt?.getTime() ?? 0;
    if (bTime !== aTime) return bTime - aTime;
    return b.id - a.id;
  });

  const sliced = allRows.slice(0, limit + 1);
  const hasMore = sliced.length > limit;
  const items = hasMore ? sliced.slice(0, limit) : sliced;

  const lastItem = items[items.length - 1];
  const nextCursor =
    hasMore && lastItem?.changedAt && lastItem?.id != null
      ? `${new Date(lastItem.changedAt).toISOString()}::${lastItem.id}::${lastItem.entityType}`
      : null;

  return {
    items,
    nextCursor,
  };
}

